class CoapMessage:
    def __init__(self):
        self.version = COAP_VERSION
        self.type = COAP_TYPE_CON
        self.token_length = 0
        self.code_class = 0
        self.code_detail = 0
        self.message_id = 0
        self.token = b""
        self.options = []
        self.payload = b""

    @staticmethod
    def parse(data):
        if data is None or len(data) < 4:
            return None

        if len(data) > MAX_MESSAGE_SIZE:
            return None

        msg = CoapMessage()

        first_byte = data[0]
        msg.version = (first_byte >> 6) & 0x03
        if msg.version != COAP_VERSION:
            return None

        msg.type = (first_byte >> 4) & 0x03
        msg.token_length = first_byte & 0x0F

        if msg.token_length > 8:
            return None

        code_byte = data[1]
        msg.code_class = (code_byte >> 5) & 0x07
        msg.code_detail = code_byte & 0x1F

        msg.message_id = (data[2] << 8) | data[3]

        offset = 4

        if msg.token_length > 0:
            if offset + msg.token_length > len(data):
                return None
            msg.token = data[offset:offset + msg.token_length]
            offset += msg.token_length

        prev_option_number = 0
        while offset < len(data):
            if data[offset] == 0xFF:
                offset += 1
                msg.payload = data[offset:]
                break

            option_delta = (data[offset] >> 4) & 0x0F
            option_length = data[offset] & 0x0F
            offset += 1

            if option_delta == 13:
                if offset >= len(data):
                    return None
                option_delta = data[offset] + 13
                offset += 1
            elif option_delta == 14:
                if offset + 1 >= len(data):
                    return None
                option_delta = ((data[offset] << 8) | data[offset + 1]) + 269
                offset += 2
            elif option_delta == 15:
                return None

            if option_length == 13:
                if offset >= len(data):
                    return None
                option_length = data[offset] + 13
                offset += 1
            elif option_length == 14:
                if offset + 1 >= len(data):
                    return None
                option_length = ((data[offset] << 8) | data[offset + 1]) + 269
                offset += 2
            elif option_length == 15:
                return None

            option_number = prev_option_number + option_delta

            if offset + option_length > len(data):
                return None

            option_value = data[offset:offset + option_length]
            offset += option_length

            msg.options.append(CoapOption(option_number, option_value))
            prev_option_number = option_number

        return msg

    def serialize(self):
        buf = bytearray()

        first_byte = ((self.version & 0x03) << 6) | \
                     ((self.type & 0x03) << 4) | \
                     (len(self.token) & 0x0F)
        buf.append(first_byte)

        code_byte = ((self.code_class & 0x07) << 5) | (self.code_detail & 0x1F)
        buf.append(code_byte)

        buf.append((self.message_id >> 8) & 0xFF)
        buf.append(self.message_id & 0xFF)

        if self.token:
            buf.extend(self.token)

        sorted_options = sorted(self.options, key=lambda o: o.number)
        prev_option_number = 0

        for opt in sorted_options:
            delta = opt.number - prev_option_number
            length = len(opt.value)

            option_byte = 0

            if delta < 13:
                option_byte |= (delta << 4)
                delta_ext = b""
            elif delta < 269:
                option_byte |= (13 << 4)
                delta_ext = bytes([delta - 13])
            else:
                option_byte |= (14 << 4)
                d = delta - 269
                delta_ext = bytes([(d >> 8) & 0xFF, d & 0xFF])

            if length < 13:
                option_byte |= length
                length_ext = b""
            elif length < 269:
                option_byte |= 13
                length_ext = bytes([length - 13])
            else:
                option_byte |= 14
                l = length - 269
                length_ext = bytes([(l >> 8) & 0xFF, l & 0xFF])

            buf.append(option_byte)
            buf.extend(delta_ext)
            buf.extend(length_ext)
            buf.extend(opt.value)

            prev_option_number = opt.number

        if self.payload:
            buf.append(0xFF)
            buf.extend(self.payload)

        return bytes(buf)

    def get_uri_path(self):
        parts = []
        for opt in self.options:
            if opt.number == COAP_OPTION_URI_PATH:
                try:
                    parts.append(opt.value.decode('utf-8'))
                except (UnicodeDecodeError, AttributeError):
                    return None
        return "/" + "/".join(parts) if parts else "/"

    def get_uri_query(self):
        queries = {}
        for opt in self.options:
            if opt.number == COAP_OPTION_URI_QUERY:
                try:
                    q = opt.value.decode('utf-8')
                    if '=' in q:
                        k, v = q.split('=', 1)
                        queries[k] = v
                    else:
                        queries[q] = ""
                except (UnicodeDecodeError, AttributeError):
                    pass
        return queries


class RateLimiter:
    """Simple per-IP rate limiter for resource-constrained devices."""

    def __init__(self, window_seconds=RATE_LIMIT_WINDOW, max_requests=MAX_REQUESTS_PER_WINDOW):
        self.window = window_seconds
        self.max_requests = max_requests
        self._clients = {}
        self._max_tracked_clients = 50

    def is_allowed(self, client_addr):
        now = time.time()
        client_key = str(client_addr[0])

        self._cleanup_expired(now)

        if client_key not in self._clients:
            if len(self._clients) >= self._max_tracked_clients:
                oldest_key = min(self._clients, key=lambda k: self._clients[k][1])
                del self._clients[oldest_key]
            self._clients[client_key] = [1, now]
            return True

        count, window_start = self._clients[client_key]

        if now - window_start > self.window:
            self._clients[client_key] = [1, now]
            return True

        if count >= self.max_requests:
            return False

        self._clients[client_key][0] += 1
        return True

    def _cleanup_expired(self, now):
        expired = [k for k, v in self._clients.items() if now - v[1] > self.window * 2]
        for k in expired:
            del self._clients[k]


class SimpleAuth:
    """Simple token-based authentication using URI query parameter."""

    def __init__(self, secret_key):
        self._secret = secret_key
        self._valid_tokens = set()

    def add_token(self, token):
        if isinstance(token, str):
            token = token.encode('utf-8')
        self._valid_tokens.add(token)

    def remove_token(self, token):
        if isinstance(token, str):
            token = token.encode('utf-8')
        self._valid_tokens.discard(token)

    def is_authorized(self, request_msg):
        queries = request_msg.get_uri_query()
        token = queries.get("token", "")
        if not token:
            return False
        if isinstance(token, str):
            token = token.encode('utf-8')
        return token in self._valid_tokens


def _sanitize_payload(payload, max_len=COAP_MAX_PAYLOAD):
    """Sanitize and validate incoming payload data."""
    if payload is None:
        return b""
    if len(payload) > max_len:
        return None
    for b in payload:
        if b < 0x20 and b not in (0x09, 0x0A, 0x0D):
            if b == 0x00:
                return None
    return payload


def _validate_numeric_value(value_str, min_val=None, max_val=None):
    """Validate a numeric string value within bounds."""
    try:
        val = float(value_str)
        if min_val is not None and val < min_val:
            return None
        if max_val is not None and val > max_val:
            return None
        return val
    except (ValueError, TypeError):
        return None


class DeviceState:
    """Holds the current state of device sensors and actuators."""

    def __init__(self):
        self.temperature = 22.5
        self.light_state = False
        self.light_brightness = 0
        self._temp_read_count = 0

    def read_temperature(self):
        """Simulate reading temperature from sensor."""
        self._temp_read_count += 1
        try:
            import machine
            adc = machine.ADC(0)
            raw = adc.read()
            self.temperature = round((raw / 1024.0) * 100.0 - 20.0, 1)
        except (ImportError, Exception):
            variation = ((self._temp_read_count * 7 + 13) % 20 - 10) / 10.0
            self.temperature = round(22.5 + variation, 1)
        return self.temperature

    def set_light(self, state, brightness=None):
        """Set light actuator state."""
        if isinstance(state, str):
            state = state.lower() in ("1", "true", "on", "yes")
        self.light_state = bool(state)
        if brightness is not None:
            b = _validate_numeric_value(str(brightness), 0, 100)
            if b is not None:
                self.light_brightness = int(b)
        elif not self.light_state:
            self.light_brightness = 0

        try:
            import machine
            pin = machine.Pin(2, machine.Pin.OUT)
            pin.value(1 if self.light_state else 0)
            if brightness is not None:
                pwm = machine.PWM(machine.Pin(2))
                pwm.duty(int(self.light_brightness * 10.23))
        except (ImportError, Exception):
            pass

        return self.light_state, self.light_brightness

    def get_light_status(self):
        return {
            "state": "on" if self.light_state else "off",
            "brightness": self.light_brightness
        }


class CoapResource:
    """Represents a CoAP resource with handlers for different methods."""

    def __init__(self, path, get_handler=None, put_handler=None, requires_auth=False):
        self.path = path
        self._get_handler = get_handler
        self._put_handler = put_handler
        self.requires_auth = requires_auth

    def handle_get(self, request):
        if self._get_handler:
            return self._get_handler(request)
        return COAP_RESPONSE_METHOD_NOT_ALLOWED, b"Method Not Allowed"

    def handle_put(self, request):
        if self._put_handler:
            return self._put_handler(request)
        return COAP_RESPONSE_METHOD_NOT_ALLOWED, b"Method Not Allowed"


class CoapServer:
    """Lightweight CoAP server for MicroPython IoT devices."""

    def __init__(self, host="0.0.0.0", port=COAP_PORT, enable_auth=True):
        self._host = host
        self._port = port
        self._resources = {}
        self._device = DeviceState()
        self._rate_limiter = RateLimiter()
        self._auth = SimpleAuth(SHARED_SECRET_KEY)
        self._enable_auth = enable_auth
        self._sock = None
        self._running = False

        self._auth.add_token("device_token_001")
        self._auth.add_token("mesh_node_key_42")

        self._register_default_resources()

    def _register_default_resources(self):
        self.add_resource(
            "/sensors/temp",
            get_handler=self._handle_temp_get,
            put_handler=None,
            requires_auth=False
        )

        self.add_resource(
            "/actuators/light",
            get_handler=self._handle_light_get,
            put_handler=self._handle_light_put,
            requires_auth=True
        )

        self.add_resource(
            "/.well-known/core",
            get_handler=self._handle_discovery,
            put_handler=None,
            requires_auth=False
        )

        self.add_resource(
            "/device/info",
            get_handler=self._handle_device_info_get,
            put_handler=None,
            requires_auth=False
        )

    def add_resource(self, path, get_handler=None, put_handler=None, requires_auth=False):
        """Register a new CoAP resource."""
        if not path.startswith("/"):
            path = "/" + path
        path = path.rstrip("/") if path != "/" else path
        self._resources[path] = CoapResource(path, get_handler, put_handler, requires_auth)

    def _handle_temp_get(self, request):
        temp = self._device.read_temperature()
        payload = '{{"temperature":{:.1f},"unit":"celsius"}}'.format(temp)
        return COAP_RESPONSE_CONTENT, payload.encode('utf-8')

    def _handle_light_get(self, request):
        status = self._device.get_light_status()
        payload = '{{"state":"{}","brightness":{}}}'.format(
            status["state"], status["brightness"]
        )
        return COAP_RESPONSE_CONTENT, payload.encode('utf-8')

    def _handle_light_put(self, request):
        payload = _sanitize_payload(request.payload)
        if payload is None:
            return COAP_RESPONSE_BAD_REQUEST, b"Invalid payload"

        if not payload:
            return COAP_RESPONSE_BAD_REQUEST, b"Empty payload"

        try:
            payload_str = payload.decode('utf-8').strip()
        except UnicodeDecodeError:
            return COAP_RESPONSE_BAD_REQUEST, b"Invalid encoding"

        state = None
        brightness = None

        if payload_str.startswith("{"):
            try:
                import ujson as json
            except ImportError:
                import json

            try:
                data = json.loads(payload_str)
            except (ValueError, Exception):
                return COAP_RESPONSE_BAD_REQUEST, b"Invalid JSON"

            if not isinstance(data, dict):
                return COAP_RESPONSE_BAD_REQUEST, b"Expected JSON object"

            if "state" in data:
                state_val = str(data["state"]).lower()
                if state_val not in ("on", "off", "true", "false", "1", "0", "yes", "no"):
                    return COAP_RESPONSE_BAD_REQUEST, b"Invalid state value"
                state = state_val in ("on", "true", "1", "yes")

            if "brightness" in data:
                brightness = _validate_numeric_value(data["brightness"], 0, 100)
                if brightness is None:
                    return COAP_RESPONSE_BAD_REQUEST, b"Brightness must be 0-100"
        else:
            lower = payload_str.lower()
            if lower in ("on", "off", "true", "false", "1", "0"):
                state = lower in ("on", "true", "1")
            else:
                return COAP_RESPONSE_BAD_REQUEST, b"Invalid payload format"

        if state is None and brightness is None:
            return COAP_RESPONSE_BAD_REQUEST, b"No valid fields"

        if state is None:
            state = self._device.light_state

        self._device.set_light(state, brightness)
        status = self._device.get_light_status()
        resp_payload = '{{"state":"{}","brightness":{}}}'.format(
            status["state"], status["brightness"]
        )
        return COAP_RESPONSE_CHANGED, resp_payload.encode('utf-8')

    def _handle_discovery(self, request):
        links = []
        for path, resource in self._resources.items():
            if path == "/.well-known/core":
                continue
            link = '<{}>'.format(path)
            if resource._get_handler and resource._put_handler:
                link += ';rt="observable";if="sensor actuator"'
            elif resource._get_handler:
                link += ';rt="sensor";if="sensor"'
            links.append(link)
        payload = ",".join(links)
        return COAP_RESPONSE_CONTENT, payload.encode('utf-8')

    def _handle_device_info_get(self, request):
        try:
            import uos
            sysname = uos.uname().sysname
        except (ImportError, AttributeError):
            sysname = "micropython"

        payload = '{{"device":"iot-node","platform":"{}","resources":{}}}'.format(
            sysname, len(self._resources)
        )
        return COAP_RESPONSE_CONTENT, payload.encode('utf-8')

    def _build_response(self, request, code_tuple, payload=b""):
        response = CoapMessage()
        response.version = COAP_VERSION

        if request.type == COAP_TYPE_CON:
            response.type = COAP_TYPE_ACK
        else:
            response.type = COAP_TYPE_NON

        response.code_class = code_tuple[0]
        response.code_detail = code_tuple[1]
        response.message_id = request.message_id
        response.token = request.token

        response.options.append(
            CoapOption(COAP_OPTION_CONTENT_FORMAT, bytes([CONTENT_FORMAT_JSON]))
        )

        if isinstance(payload, str):
            payload = payload.encode('utf-8')
        response.payload = payload

        return response

    def _process_request(self, data, addr):
        """Process an incoming CoAP request and return response bytes."""
        request = CoapMessage.parse(data)
        if request is None:
            return None

        if not self._rate_limiter.is_allowed(addr):
            response = self._build_response(
                request, COAP_RESPONSE_BAD_REQUEST, b"Rate limit exceeded"
            )
            return response.serialize()

        uri_path = request.get_uri_path()
        if uri_path is None:
            response = self._build_response(
                request, COAP_RESPONSE_BAD_REQUEST, b"Invalid URI"
            )
            return response.serialize()

        resource = self._resources.get(uri_path)
        if resource is None:
            response = self._build_response(
                request, COAP_RESPONSE_NOT_FOUND, b"Resource not found"
            )
            return response.serialize()

        if self._enable_auth and resource.requires_auth:
            if not self._auth.is_authorized(request):
                response = self._build_response(
                    request, COAP_RESPONSE_UNAUTHORIZED, b"Unauthorized"
                )
                return response.serialize()

        method = request.code_detail
        code = None
        payload = b""

        try:
            if request.code_class == 0 and method == COAP_METHOD_GET:
                code, payload = resource.handle_get(request)
            elif request.code_class == 0 and method == COAP_METHOD_PUT:
                code, payload = resource.handle_put(request)
            else:
                code = COAP_RESPONSE_METHOD_NOT_ALLOWED
                payload = b"Method Not Allowed"
        except Exception as e:
            print("Error handling request for {}: {}".format(uri_path, e))
            code = COAP_RESPONSE_INTERNAL_ERROR
            payload = b"Internal Server Error"

        response = self._build_response(request, code, payload)
        return response.serialize()

    def start(self):
        """Start the CoAP server."""
        self._sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self._sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self._sock.bind((self._host, self._port))

        try:
            self._sock.settimeout(1.0)
        except Exception:
            pass

        self._running = True
        print("CoAP server started on {}:{}".format(self._host, self._port))
        print("Registered resources:")
        for path in sorted(self._resources.keys()):
            r = self._resources[path]
            methods = []
            if r._get_handler:
                methods.append("GET")
            if r._put_handler:
                methods.append("PUT")
            auth_str = " [AUTH]" if r.requires_auth else ""
            print("  {} [{}]{}".format(path, ", ".join(methods), auth_str))

        while self._running:
            try:
                data, addr = self._sock.recvfrom(MAX_MESSAGE_SIZE)
                if data:
                    response_data = self._process_request(data, addr)
                    if response_data:
                        self._sock.sendto(response_data, addr)
            except OSError as e:
                if hasattr(e, 'args') and e.args[0] == 11:
                    continue
                if hasattr(e, 'errno'):
                    import errno
                    if e.errno == getattr(errno, 'ETIMEDOUT', None) or \
                       e.errno == getattr(errno, 'EAGAIN', None):
                        continue
                if "timed out" in str(e).lower() or "EAGAIN" in str(e):
                    continue
                print("Socket error: {}".format(e))
            except KeyboardInterrupt:
                print("\nShutting down...")
                self._running = False
            except Exception as e:
                print("Unexpected error: {}".format(e))

        self.stop()

    def stop(self):
        """Stop the CoAP server."""
        self._running = False
        if self._sock:
            try:
                self._sock.close()
            except Exception:
                pass
            self._sock = None
        print("CoAP server stopped.")


def connect_wifi(ssid, password):
    """Connect to WiFi (for ESP32/ESP8266)."""
    try:
        import network
        wlan = network.WLAN(network.STA_IF)
        wlan.active(True)
        if not wlan.isconnected():
            print("Connecting to WiFi '{}'...".format(ssid))
            wlan.connect(ssid, password)
            timeout = 20
            while not wlan.isconnected() and timeout > 0:
                time.sleep(1)
                timeout -= 1
            if wlan.isconnected():
                print("Connected! IP: {}".format(wlan.ifconfig()[0]))
                return True
            else:
                print("WiFi connection failed.")
                return False
        else:
            print("Already connected. IP: {}".format(wlan.ifconfig()[0]))
            return True
    except ImportError:
        print("Running on non-WiFi platform, skipping WiFi setup.")
        return True


